class Solution:
    def networkDelayTime(self, times, n, k):
        INF = float('inf')
        dist = {i: INF for i in range(1, n + 1)}
        dist[k] = 0
        for _ in range(n - 1):
            for u, v, w in times:
                if dist[u] != INF and dist[u] + w < dist[v]:
                    dist[v] = dist[u] + w
        m = max(dist.values())
        return -1 if m == INF else m

